            }

            code,
            kbd,
            samp {
                font-family: monospace, monospace;
                font-size: 1em;
            }

            small {
                font-size: 80%;
            }

            sub,
            sup {
                font-size: 75%;
                line-height: 0;
                position: relative;
                vertical-align: baseline;
            }

            sub {
                bottom: -0.25em;
            }

            sup {
                top: -0.5em;
            }

            button,
            input,
            optgroup,
            select,
            textarea {
                font-family: inherit;
                font-size: 100%;
                margin: 0;
            }

            button,
            input {
                overflow: visible;
            }

            button,
            select {
                text-transform: none;
            }

            [type="button"],
            [type="reset"],
            [type="submit"],
            button {
                -webkit-appearance: button;
            }

            fieldset {
                padding: 0.35em 0.75em 0.625em;
            }

            legend {
                display: table;
                max-width: 100%;
                padding: 0;
                white-space: normal;
            }

            progress {
                vertical-align: baseline;
            }

            textarea {
                overflow: auto;
            }

            [type="number"]::-webkit-inner-spin-button,
            [type="number"]::-webkit-outer-spin-button {
                height: auto;
            }

            [type="search"] {
                -webkit-appearance: textfield;
                outline-offset: -2px;
            }

            [type="search"]::-webkit-search-decoration {
                -webkit-appearance: none;
            }

            ::-webkit-file-upload-button {
                -webkit-appearance: button;
                font: inherit;
            }

            details {
                display: block;
            }

            summary {
                display: list-item;
            }

            template {
                display: none;
            }
        }

        @layer ingr_layer_normalize;
        @layer ingr_layer_priority_low;

        :root {
            --ei_base_height: 2.25rem;
            --ei_base_spacing: 0.375rem;
        }

        .ei_density_high {
            --ei_base_height: 2rem;
            --ei_base_spacing: 0.25rem;
        }

        .ei_density_medium {
            --ei_base_height: 2.25rem;
            --ei_base_spacing: 0.375rem;
        }

        .ei_density_low {
            --ei_base_height: 3rem;
            --ei_base_spacing: 1rem;
        }

        .a_blocappli {
            --richbtn_minheight: var(--ei_base_height);
            --input_minheight: var(--ei_base_height);
            --span_dw_cb_input_text_minheight: var(--ei_base_height);
            --listbox_minheight: var(--ei_base_height);
            --inputlblfloat_input_minheight: var(--input_minheight);
            --table_caption_padding: calc(var(--ei_base_spacing) * 1.5);
            --table_layout_head_cell_padding: var(--ei_base_spacing) calc(var(--ei_base_spacing) * 1.5);
            --table_layout_cell_padding: var(--ei_base_spacing) calc(var(--ei_base_spacing) * 1.5);
            --table_head_cell_padding: var(--ei_base_spacing) calc(var(--ei_base_spacing) * 1.5);
            --table_cell_padding: var(--ei_base_spacing) calc(var(--ei_base_spacing) * 1.5);
        }

        *,
        :after,
        :before {
            box-sizing: border-box;
        }

