        .ei_inputpassword-reveal {
            position: relative;
            display: block;
        }

        .ei_hintedinput .ei_inputpassword-reveal {
            width: 100%;
        }

        .ei_inputpassword-reveal input[type="password"],
        .ei_inputpassword-reveal input[type="text"] {
            margin-bottom: 0;
            padding-right: 2.5rem;
            width: 100% !important;
        }

        .ei_inputpassword-reveal .ei_inputpassword__reveal {
            -webkit-appearance: none;
            -moz-appearance: none;
            appearance: none;
            border: 0;
            background: 0 0;
            padding: 0;
            position: absolute;
            top: 50%;
            right: 0;
            -webkit-transform: translateY(-50%);
            transform: translateY(-50%);
            width: 2.5rem;
            height: 100%;
            border-radius: 0 0.5rem 0.5rem 0;
        }

        .ei_inputpassword-reveal .ei_inputpassword__reveal:hover {
            cursor: pointer;
        }

        .ei_inputpassword-reveal .ei_inputpassword__reveal:focus-visible {
            outline: 0.125rem solid #003192;
            outline-offset: -0.0625rem;
        }

        .ei_inputpassword-reveal .ei_inputpassword__reveal-icon:before {
            position: absolute;
            top: 50%;
            left: 50%;
            -webkit-transform: translate(-50%, -50%);
            transform: translate(-50%, -50%);
        }

        .ei_inputpassword-reveal .ei_inputpassword__reveal-icon:before {
            -webkit-mask-position: center;
            mask-position: center;
            -webkit-mask-repeat: no-repeat;
            mask-repeat: no-repeat;
            -webkit-mask-size: 1.25rem;
            mask-size: 1.25rem;
            display: inline-block;
            min-width: 1.25rem;
            min-height: 1.25rem;
            content: "";
            vertical-align: middle;
        }

        .ei_inputpassword-reveal .ei_inputpassword__reveal-icon:before {
            -webkit-mask-image:
                /*savepage-url=../../commun/svg/F0F88.svg*/
                var(--savepage-url-18);
            mask-image:
                /*savepage-url=../../commun/svg/F0F88.svg*/
                var(--savepage-url-18);
        }

        .ei_inputpassword-reveal .ei_inputpassword__reveal-icon:before {
            background: #5e5e5e;
        }

        .ei_inputpassword-reveal input[type="text"]+.ei_inputpassword__reveal .ei_inputpassword__reveal-icon:before {
            -webkit-mask-image:
                /*savepage-url=../../commun/svg/F0133.svg*/
                url();
            mask-image:
                /*savepage-url=../../commun/svg/F0133.svg*/
                url();
        }

        .ei_inputpassword-reveal input[type="text"]+.ei_inputpassword__reveal .ei_inputpassword__reveal-icon:before {
            -webkit-mask-position: center;
