        .a_blocappli input[type="checkbox"] {
            margin: 0.0625rem 0.5rem 0.0625rem 0.25rem;
            -webkit-appearance: none;
            -moz-appearance: none;
            appearance: none;
            padding: 0;
            display: inline-block;
            position: relative;
            transition: none;
            vertical-align: text-bottom;
            background: #fff;
            width: 1rem;
            height: 1rem;
            border: 0.0625rem solid #737373;
            border-radius: 0.375rem;
        }

        .a_blocappli input[type="checkbox"]:before {
            position: absolute;
            top: 50%;
            left: 50%;
            -webkit-transform: translate(-50%, -50%);
            transform: translate(-50%, -50%);
        }

        .a_blocappli input[type="checkbox"]:checked,
        .a_blocappli input[type="checkbox"]:checked:hover {
            background: #003192;
            outline: 0.125rem solid #ffffff !important;
            border-color: #003192;
        }

        .a_blocappli input[type="checkbox"]:checked:before,
        .a_blocappli input[type="checkbox"]:checked:hover:before {
            -webkit-mask-image:
                /*savepage-url=../../commun/svg/F021D.svg*/
                url();
            mask-image:
                /*savepage-url=../../commun/svg/F021D.svg*/
                url();
        }

        .a_blocappli input[type="checkbox"]:checked:before,
        .a_blocappli input[type="checkbox"]:checked:hover:before {
            -webkit-mask-position: center;
            mask-position: center;
            -webkit-mask-repeat: no-repeat;
            mask-repeat: no-repeat;
            -webkit-mask-size: 0.8125rem;
            mask-size: 0.8125rem;
            display: inline-block;
            min-width: 0.8125rem;
            min-height: 0.8125rem;
            content: "";
