        .a_blocappli input[type="checkbox"]:indeterminate:before {
            -webkit-mask-image:
                /*savepage-url=../../commun/svg/F0413.svg*/
                url();
            mask-image:
                /*savepage-url=../../commun/svg/F0413.svg*/
                url();
        }

        .a_blocappli input[type="checkbox"]:indeterminate:before {
