        .a_blocappli input[type="checkbox"]:indeterminate:before {
            background: #000;
        }

        .a_blocappli input[type="checkbox"]:disabled {
            cursor: default;
        }

        .a_blocappli input[type="checkbox"]:disabled:checked:before {
