        .a_blocappli input[type="radio"] {
            margin: 0.0625rem 0.5rem 0.0625rem 0.25rem;
            -webkit-appearance: none;
            -moz-appearance: none;
            appearance: none;
            display: inline-block;
            vertical-align: text-bottom;
            padding: 0;
            position: relative;
            border-radius: 50%;
            transition: none;
            background: #fff;
            width: 1.125rem;
            height: 1.125rem;
            border: 0.0625rem solid #737373;
        }

        .a_blocappli input[type="radio"]:before {
            content: "";
            display: none;
            position: absolute;
            top: 50%;
            left: 50%;
            -webkit-transform: translate(-50%, -50%);
            transform: translate(-50%, -50%);
            width: 0.625rem;
            height: 0.625rem;
            border-radius: 50%;
            background: #003192;
