        @-webkit-keyframes fpFadeInDown {
            from {
                opacity: 0;
                -webkit-transform: translate3d(0, -1.25rem, 0);
                transform: translate3d(0, -1.25rem, 0);
            }

            to {
                opacity: 1;
                -webkit-transform: translate3d(0, 0, 0);
                transform: translate3d(0, 0, 0);
            }
        }

        @keyframes fpFadeInDown {
            from {
                opacity: 0;
                -webkit-transform: translate3d(0, -1.25rem, 0);
                transform: translate3d(0, -1.25rem, 0);
            }

            to {
                opacity: 1;
                -webkit-transform: translate3d(0, 0, 0);
                transform: translate3d(0, 0, 0);
            }
        }

        .flatpickr-calendar {
            position: absolute;
            opacity: 0;
            display: none;
            visibility: hidden;
            -webkit-animation: none;
            animation: none;
            direction: ltr;
            touch-action: manipulation;
            background: #fff;
            text-align: center;
            width: 16.5625rem;
            padding: 0;
            font-size: 0.875rem;
            line-height: 1.5rem;
            box-shadow: 0 0 1.25rem 0 rgba(0, 0, 0, 0.1);
            border-radius: 0.5rem;
        }

        .flatpickr-calendar:focus {
            outline: 0;
        }

        .flatpickr-calendar.inline,
        .flatpickr-calendar.open {
            opacity: 1;
            visibility: visible;
            max-height: 40rem;
        }

        .flatpickr-calendar.open {
            display: inline-block;
            z-index: 99999;
        }

        .flatpickr-calendar.open.animate {
            -webkit-animation: fpFadeInDown 0.3s cubic-bezier(0.23, 1, 0.32, 1);
            animation: fpFadeInDown 0.3s cubic-bezier(0.23, 1, 0.32, 1);
        }

        .flatpickr-calendar.open.static {
            display: block;
            z-index: 999;
        }

        .flatpickr-calendar.inline {
            display: block;
            position: relative;
            top: 0.125rem;
        }

        .flatpickr-calendar.static {
            position: absolute;
            top: calc(100% - 0.125rem);
        }

        .flatpickr-calendar.multiMonth .flatpickr-days .dayContainer:nth-child(n + 1) .flatpickr-day.inRange:nth-child(7n + 7) {
            box-shadow: none !important;
        }

        .flatpickr-calendar.multiMonth .flatpickr-days .dayContainer:nth-child(n + 2) .flatpickr-day.inRange:nth-child(7n + 1) {
            box-shadow: 0.313rem 0 0 #e0e0e0;
        }

        .flatpickr-calendar .hasWeeks .dayContainer {
            border-bottom: 0;
            border-left: 0;
            border-bottom-right-radius: 0;
            border-bottom-left-radius: 0;
        }

        .flatpickr-calendar .shortcut-buttons-flatpickr-button {
            cursor: pointer;
            line-height: 1;
            background: #fff;
            color: #003192;
            font-weight: 500;
            font-size: 1rem;
            margin: 0 0 0.625rem;
            padding: 0.5rem 1.5rem;
            transition: all 0.2s ease-in;
            border: 0.125rem solid #003192;
            border-radius: 1.5rem;
        }

        .flatpickr-calendar .shortcut-buttons-flatpickr-button:focus,
        .flatpickr-calendar .shortcut-buttons-flatpickr-button:hover {
            background: #003192;
            color: #fff;
            border-color: #003192;
        }

        .flatpickr-wrapper {
            position: relative;
            display: inline-block;
        }

        .flatpickr-innerContainer {
            display: flex;
            overflow: hidden;
        }

        .flatpickr-rContainer {
            display: inline-block;
            padding: 0.625rem 0 0;
        }

        .flatpickr-months {
            display: flex;
            align-items: center;
            width: 100%;
            height: 3.5rem;
            background: #003192;
            border-radius: 0.5rem 0.5rem 0 0;
        }

        .flatpickr-months .flatpickr-month {
            user-select: none;
            -webkit-user-select: none;
            flex: 1;
