        .bloctel_css {
            display: inline-block;
            width: auto;
            border-radius: 1.875rem;
            position: relative;
            background: 0 0;
            background-color: #fff;
            margin-bottom: 1rem;
            box-sizing: content-box;
            line-height: normal;
        }

        .bloctel_css:after,
        .bloctel_css:before {
            content: " ";
            position: absolute;
            box-sizing: inherit;
            top: 50%;
            -webkit-transform: translateY(-50%);
            transform: translateY(-50%);
        }

        .bloctel_css .num {
            padding: 0;
            margin: 0;
            display: flex;
