            letter-spacing: 0.5px;
            margin-right: 0.625rem;
            border-radius: 1.875rem;
            color: #fff;
            font-weight: 700;
            padding: 0.3125rem 0.9375rem;
        }

        .bloctel_css .num:after {
            content: "";
            position: absolute;
            border-radius: 1.875rem;
            left: 0;
            top: 0;
            right: 0;
            bottom: 0;
        }

        .bloctel_css .tarif {
            color: #9ea3a6;
            position: absolute;
            text-transform: uppercase;
            top: 1.875rem;
            width: auto;
            font-size: 0.625rem;
            margin: 0;
