            border: 0.125rem solid #9ea3a6;
        }

        .bloctel_css:before {
            width: 0;
            height: 0;
            border: solid transparent;
            border-color: transparent transparent transparent #fff;
            pointer-events: none;
        }

        .bloctel_css:after {
            border: solid #fff;
            border-radius: 50%;
            z-index: 10;
        }

        .bloctel_css.xsmall:before {
            border-width: 0.1875rem 0.1875rem 0.1875rem 0.375rem;
            left: 0.6875rem;
        }

        .bloctel_css.xsmall:after {
