            height: 1rem;
            width: 1rem;
            left: 0.375rem;
        }

        .bloctel_css.small .num {
            font-size: 0.9375rem;
        }

        .bloctel_css.small .num_title {
            padding: 0.3125rem 0.5rem 0.3125rem 1.875rem;
        }

