        .ei_maquetteur body {
            background: #fff none !important;
            padding: 0 !important;
        }

        body.ei_maquetteur {
            background: #fff none !important;
            padding: 0 !important;
        }

        @media print {
            .eir_printhide {
                display: none !important;
            }

            body {
                background: #fff;
            }

            body a {
                text-decoration: none;
            }

            body ul {
                padding: 0;
            }

            body * {
                font-size: 10pt;
                font-family: Arial, sans-serif !important;
            }

            .ei_header {
                box-shadow: none;
                background: 0 0;
                padding: 0;
            }

            .ei_header__logo {
                padding: 1.5rem 0 0.25rem;
            }

            .ei_mode_sticky .ei_header {
                position: relative;
            }

            .ei_contener {
                max-width: none;
            }

            .a_blocappli {
                box-shadow: none;
                background: 0 0;
                padding: 0;
                margin: 0;
            }

            .a_blocfctl,
            .ei_mainblocfctl {
                box-shadow: none;
                background: 0 0;
                padding: 0;
            }

            select {
                -webkit-print-color-adjust: exact;
                color-adjust: exact;
            }

            .ei_togglebtn {
                -webkit-print-color-adjust: exact;
                color-adjust: exact;
            }

            .ei_titleblock {
                margin: 0 0 0.5rem;
            }

            .ei_titleblock .ei_titlecontent {
                padding: 0;
            }

            .a_blocfctltitre,
            .ei_mainblocfctl_title {
                padding: 0 !important;
            }

            .a_titre1,
            p.a_titre1 {
                box-shadow: none;
                background: 0 0;
                padding: 0;
                color: #757575;
            }

            .blocpaginb {
                margin: 0;
            }

            .blocpaginb .pgcou,
            .blocpaginb .pgnum,
            .blocpaginb a {
                display: none;
            }

            table {
                margin: 0 0 0.3125rem;
            }

            table .a_actions {
                display: none;
            }

            table a.triasc,
            table a.tridesc,
            table a.trioff {
                padding-right: 0;
            }

            table a.triasc:before,
            table a.tridesc:before,
            table a.trioff:before {
                display: none;
            }

            .restriction {
                margin: 0.25rem 0;
            }

            .restriction .ei_restriction__item:not(.sel),
            .restriction:before {
                display: none;
            }

            .restriction .ei_restriction__item.sel {
                display: flex;
                justify-content: center;
            }

            .restriction .ei_restriction__item.sel:before {
                -webkit-print-color-adjust: exact;
                color-adjust: exact;
            }

            .blocmsg,
            .bloctxt {
